assignments.value:
={{ 
  // 1. ROBUST HISTORY LOCK
  // Check BOTH locations: inside 'fields' (standard) AND at top level (flattened)
  (
    ($('Check User Status').first()?.json?.fields?.Status || $('Check User Status').first()?.json?.Status || "").toString().includes('LinkSent')
  ) 
  || 
  // 2. NEW LINK CHECK
  // If the bot just sent the link right now
  (
    ( $('AI Agent').item.json.output.response_to_user|| "").toLowerCase().includes("wa.me")
  )

  ? "LinkSent" 
  : "Pending" 
}}

parameters.jsonBody:
